import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        if N % 2 == 1:
            out_lines.append('-1')
        else:
            perm = []
            for i in range(1, N + 1, 2):
                perm.append(str(i + 1))
                perm.append(str(i))
            out_lines.append(' '.join(perm))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

