let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  if (N % 2 === 1) {
    out.push('-1');
    continue;
  }
  let parts = [];
  for (let i = 1; i <= N; i += 2) {
    parts.push(String(i + 1), String(i));
  }
  out.push(parts.join(' '));
}
